INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('08-mo-tang-empire-u-plus',2,8,'MỞ TẦNG EMPIRE U++ (WHAT)','Mo tang Empire U++ - What',8,'draft','2026-06-20T11:05:43Z','2026-06-20T11:05:43Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2672ec82-9cd5-4d3f-9fcf-9090e1395e10','08-mo-tang-empire-u-plus',NULL,2,'TẦNG 2 - EMPIRE U++ (WHAT)','tang-2-empire-u-what',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a42978ce-fded-4ab2-bbb5-e9ba432e6614','2672ec82-9cd5-4d3f-9fcf-9090e1395e10',0,'text','Khi tôi đã trả lời xong câu hỏi “vì sao phải có hệ điều hành”, câu hỏi tiếp theo tự nhiên hiện ra là: **vậy mình đang xây cái gì?** Ở tầng này, tôi không muốn nhìn hệ thống như những mảnh ghép rời rạc nữa. Tôi muốn nhìn nó như một bức tranh đầy đủ, nơi từng phần đều có vai trò riêng, nhưng lại cùng kéo nhau chạy về một hướng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1db0abef-9f72-492c-9481-12b8f3da430f','2672ec82-9cd5-4d3f-9fcf-9090e1395e10',1,'text','Với Dental Empire OS, tầng 2 chính là phần tôi gọi là **Hệ sinh thái tăng trưởng Master Map**. Đây là nơi mọi thứ bắt đầu lộ diện rất rõ: từ Personal Brand của bác sĩ hoặc founder, đến Media Network, đến Clinic System, rồi đi qua Growth Engine, Trust Assets, Customer Journey, Patient Experience, Referral Ecosystem, Patient Community và cuối cùng là lớp Education/Product Layer. Tất cả không đứng riêng lẻ; chúng quay vòng, đẩy nhau, nuôi nhau, và tạo thành một bánh đà tăng trưởng có thể vận hành lặp đi lặp lại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fe01b0de-64f2-4fcf-a4e3-61b2cdb37815','2672ec82-9cd5-4d3f-9fcf-9090e1395e10',2,'text','Điều tôi thích nhất ở bức tranh này là nó cho ta thấy tăng trưởng không đến từ một nguồn duy nhất. Nó không chỉ đến từ content, không chỉ đến từ ads, không chỉ đến từ sale, cũng không chỉ đến từ tay nghề. Tăng trưởng thật sự đến khi những phần ấy kết nối với nhau thành một dòng chảy: content tạo sự chú ý, ads mở rộng phạm vi, CRM và sales biến quan tâm thành lịch hẹn, clinic system tạo trải nghiệm điều trị, trust assets củng cố niềm tin, patient experience nuôi sự hài lòng, referral biến sự hài lòng thành lan truyền, và community giữ mối quan hệ lâu dài.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('85b73d20-9122-4b23-90d3-63c0fc23bef7','2672ec82-9cd5-4d3f-9fcf-9090e1395e10',3,'text','Nói đơn giản hơn, đây là phần tôi nhìn thấy rõ **“giao diện”** của hệ điều hành. Tôi không chỉ nhìn từng bộ phận, mà nhìn xem chúng tác động lên nhau ra sao. Personal Brand không thể mạnh nếu Media Network yếu. Media Network không thể tạo chuyển đổi nếu Trust Assets chưa đủ dày. Trust Assets không thể tự sống nếu Customer Journey và Patient Experience chưa được thiết kế tốt. Và Referral Ecosystem cũng không thể bền nếu phía sau không có một Clinic System đủ tốt để giữ chất lượng thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1c887270-266a-4b70-9ac7-73b26cd0104a','2672ec82-9cd5-4d3f-9fcf-9090e1395e10',4,'text','Từ góc nhìn này, Dental Empire OS không còn là một hệ thống quản trị khô cứng. Nó giống một cơ thể sống hơn: có phần thu hút, có phần chuyển hóa, có phần giữ chân, có phần khuếch đại. Mỗi tầng trong nó không chỉ làm nhiệm vụ riêng, mà còn bơm năng lượng cho tầng phía trên và tầng phía sau, để toàn bộ hệ sinh thái cứ thế quay vòng, lớn lên và tự tạo ra đà phát triển mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2c007a4b-2624-4826-a93d-b90c987f2fe8','08-mo-tang-empire-u-plus',NULL,2,'8.1 Tầng 2 trả lời câu hỏi gì?','81-tang-2-tra-loi-cau-hoi-gi',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e73843b9-49d2-4cf7-b2cd-e5de32ab8474','2c007a4b-2624-4826-a93d-b90c987f2fe8',5,'text','Tầng 2 trả lời câu hỏi: **làm sao để các phần của phòng khám kết nối với nhau thành một hệ sinh thái tăng trưởng bền vững**. Ở tầng này, ta không nhìn từng công cụ riêng lẻ nữa, mà nhìn cách thương hiệu, nội dung, niềm tin, hành trình khách hàng, trải nghiệm bệnh nhân, giới thiệu và cộng đồng cùng quay vòng để tạo ra đà phát triển.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ba9696c9-a705-4122-8b6d-832a6db62316','2c007a4b-2624-4826-a93d-b90c987f2fe8',6,'text','- Tầng này trả lời những câu hỏi rất thực: - Khách hàng biết phòng khám từ đâu?- Họ tin bằng cách nào?- Hành trình của họ diễn ra ra sao?- Điều gì khiến họ ở lại?- Điều gì khiến họ giới thiệu người khác?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('39b0cbb9-fc8e-4dc6-92bf-f0f03458c9a1','2c007a4b-2624-4826-a93d-b90c987f2fe8',7,'text','Vì vậy, nếu tầng 1 là câu hỏi “vì sao phải có hệ điều hành”, thì tầng 2 là câu hỏi **“hệ điều hành ấy được khách hàng trải nghiệm như thế nào trong vận hành thật của phòng khám”**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7c265fca-43a9-426a-84a9-637fc762e68d','08-mo-tang-empire-u-plus',NULL,2,'8.2 Vì sao tăng trưởng không đến từ một điểm đơn lẻ?','82-vi-sao-tang-truong-khong-en-tu-mot-iem-on-le',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('97189944-c8f1-450e-810a-fc481cbb8576','7c265fca-43a9-426a-84a9-637fc762e68d',8,'text','Vì tăng trưởng bền vững là kết quả của một **chuỗi tương tác cộng hưởng**, không phải của một cú đẩy duy nhất. Một bài content hay có thể tạo chú ý, nhưng nếu không có trust, journey, experience và referral đi kèm thì nó chỉ dừng ở mức “được xem”, chứ chưa trở thành “được tin” hay “được giới thiệu”.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('72660624-4ddc-45c6-9f7b-4cdb86e2c2c0','7c265fca-43a9-426a-84a9-637fc762e68d',9,'text','Trong mô hình FLYWHEEL, mỗi lớp chỉ thực sự có ý nghĩa khi nó tạo lực cho lớp khác. Customer success, Patient experience, Review, Referral và Retention không phải là đầu ra cuối cùng; chúng là đầu vào cho vòng tăng trưởng tiếp theo, nên giá trị của hệ thống nằm ở chỗ nó **tích lũy đà** qua thời gian.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ce91f44a-bd88-405e-807d-c08c39fa32a3','7c265fca-43a9-426a-84a9-637fc762e68d',10,'text','Với phòng khám, điều đó càng đúng hơn. Người bệnh thường đi qua nhiều điểm chạm trước khi quyết định, từ tìm kiếm, xem thương hiệu, đọc nội dung, kiểm tra review, so sánh, đặt lịch, trải nghiệm điều trị, rồi mới giới thiệu người khác; vì thế, một điểm mạnh đơn lẻ không đủ nếu các điểm khác bị đứt gãy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4aeac4b8-ae51-488c-9489-00b100c13332','7c265fca-43a9-426a-84a9-637fc762e68d',11,'text','Nói ngắn gọn, tăng trưởng không đến từ một điểm đơn lẻ vì niềm tin không được tạo ra trong một lần chạm. Nó được tạo ra khi nhiều phần của hệ thống cùng làm đúng việc của mình, cùng lúc, đủ đều, đủ lâu, để cuối cùng tạo thành một vòng quay tự nuôi chính nó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f948fceb-adcf-4155-a4fd-68593b2d96fd','08-mo-tang-empire-u-plus',NULL,2,'8.3 Từ hệ điều hành sang hệ sinh thái tăng trưởng','83-tu-he-ieu-hanh-sang-he-sinh-thai-tang-truong',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7c27811-816c-4f7c-8709-d8a4a7902ed1','f948fceb-adcf-4155-a4fd-68593b2d96fd',12,'text','Khi một phòng khám chỉ mới có hệ điều hành, nó đã biết cách vận hành. Nhưng khi hệ điều hành đủ chín, câu hỏi tiếp theo không còn là “làm sao để chạy”, mà là “làm sao để mọi phần trong hệ thống cùng tạo ra đà cho nhau”. Từ đó, phòng khám bắt đầu đi từ operating model sang growth ecosystem: nơi thương hiệu cá nhân, truyền thông, phòng khám, niềm tin, hành trình khách hàng, trải nghiệm bệnh nhân, giới thiệu và cộng đồng không còn đứng riêng lẻ, mà vận hành như một BÁNH ĐÀ (FLYWHEEL) có khả năng tự nuôi chính nó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aac7ace7-28f1-4c8b-a6a3-247890aea8e2','f948fceb-adcf-4155-a4fd-68593b2d96fd',13,'text','Ở tầng này, tăng trưởng không còn là kết quả của một chiến dịch đơn lẻ, mà là hệ quả của một chuỗi tích lũy rất đều:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f45c0a3a-6db3-4a86-a667-8a84984b46af','f948fceb-adcf-4155-a4fd-68593b2d96fd',14,'text','- Một nội dung tốt làm tăng niềm tin- Niềm tin giúp khách bước vào hành trình- Hành trình tốt tạo trải nghiệm tốt- Trải nghiệm tốt sinh những lời giới thiệu (Referral)- Giới thiệu (referral) lại nuôi thương hiệu và cộng đồng- Rồi chính cộng đồng ấy quay lại làm mạnh thêm toàn bộ hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8923fb29-cd97-4cbe-a032-c79122eb698e','f948fceb-adcf-4155-a4fd-68593b2d96fd',15,'image',NULL,'book/08-mo-tang-empire-u-plus/0201e8a2-9e29-46ef-959e-03b570d6b1fb-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('173da196-5678-493a-991d-3efda4569c2a','08-mo-tang-empire-u-plus',NULL,2,'8.4 Cách đọc Master Map','84-cach-oc-master-map',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e43b12e9-c4c6-4752-b616-127b3657b654','173da196-5678-493a-991d-3efda4569c2a',16,'text','Cách đọc Master Map rất đơn giản: hãy đi theo dòng chảy của niềm tin. Bắt đầu từ thương hiệu cá nhân (Personal Bradning) và Media Network, rồi đi xuống nơi niềm tin được kiểm chứng trong Clinic System, sau đó được nuôi lớn bằng trải nghiệm, và được nhân lên qua Referral, cộng đồng, rồi quay lại làm mạnh thêm chính hệ sinh thái. Master Map vì thế không phải là một sơ đồ tĩnh, mà là một vòng quay sống động nơi mỗi lớp vừa là kết quả của lớp trước, vừa là lực đẩy cho lớp sau.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('16642baf-6e65-42cc-bec1-6909f1e7a242','173da196-5678-493a-991d-3efda4569c2a',17,'image',NULL,'book/08-mo-tang-empire-u-plus/d964dd15-64af-4409-8fcb-c324587b0a2c-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e5fbd092-b1ea-4ff4-994c-52799e3a69ae','08-mo-tang-empire-u-plus','173da196-5678-493a-991d-3efda4569c2a',3,'Empire Flywheel','empire-flywheel',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('851c1f6b-3aeb-4a8b-981e-3395738dc602','e5fbd092-b1ea-4ff4-994c-52799e3a69ae',18,'text','Tôi thích mô hình **Bánh xe (Flywheel)** vì nó rất gần với cách con người thật sự đi đến một niềm tin. Người bệnh hiếm khi quyết định chỉ từ một quảng cáo thoáng qua; họ cần nhiều dấu hiệu nhỏ, lặp lại, để dần thấy rằng đây là một nơi đáng tin, đáng đến, và đáng quay lại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('486e7279-5a1d-4270-a60d-dd808dd2ea9f','e5fbd092-b1ea-4ff4-994c-52799e3a69ae',19,'text','Đôi khi, dấu hiệu đầu tiên chỉ là một gương mặt bác sĩ xuất hiện trên TikTok hay YouTube, một giọng nói bình tĩnh, một đoạn chia sẻ đủ tử tế để người ta dừng lại lâu hơn. Rồi đến những nội dung hữu ích, những review thật trên Google, một website rõ ràng về dịch vụ, bảng giá và chuyên môn; từng lớp một, niềm tin được dệt nên, chậm rãi mà chắc chắn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b62a5780-8502-489e-8c89-94d765d771d0','e5fbd092-b1ea-4ff4-994c-52799e3a69ae',20,'text','Và khi niềm tin đã đủ sâu, người bệnh mới bước vào phòng khám. Nếu trải nghiệm ở đó đủ ấm, đủ rõ, đủ an tâm, họ không chỉ ở lại cho một lần điều trị; họ quay trở lại, và chính sự quay trở lại ấy lại âm thầm làm bánh xe lớn thêm, nặng thêm, và đi xa hơn',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('adad8f5f-ada1-47c3-be24-31de8d628395','08-mo-tang-empire-u-plus','173da196-5678-493a-991d-3efda4569c2a',3,'Ba trụ vận hành','ba-tru-van-hanh',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2bbee641-e16b-49c3-bbf6-6232abddf3ba','adad8f5f-ada1-47c3-be24-31de8d628395',21,'image',NULL,'book/08-mo-tang-empire-u-plus/46e2b612-08b2-4055-b027-3c3a98219549-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cde9ddf1-4ae8-458c-87f4-28736c9fa8e0','adad8f5f-ada1-47c3-be24-31de8d628395',22,'text','Empire Flywheel được nâng đỡ bởi ba trụ chính: **Personal Brand, Media Network và Clinic System**. Tôi xem đây là ba nền móng quan trọng nhất của tầng 2, vì thiếu một trong ba, hệ sinh thái sẽ khó đứng vững và vòng quay tăng trưởng sẽ nhanh chóng mất lực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3534b8b5-56d1-4683-a469-9d241735e26d','adad8f5f-ada1-47c3-be24-31de8d628395',23,'text','- **Personal Brand** là uy tín chuyên môn của bác sĩ hoặc nhà sáng lập (Founder). Đây là nơi người khác bắt đầu tin vào con người đứng sau phòng khám, tin vào cách họ nghĩ, cách họ làm và cách họ đối xử với người bệnh.- **Media Network** là hệ thống nội dung và hiện diện đa kênh, nơi câu chuyện ấy được lan tỏa qua mạng xã hội, kết quả tìm kiếm và các nền tảng truyền thông; nó mở rộng độ phủ và giúp niềm tin được nhìn thấy nhiều lần, ở nhiều điểm chạm khác nhau.- **Clinic System** là nơi niềm tin được xác nhận bằng trải nghiệm thật trong tư vấn, điều trị, CSKH và tái khám; đây là chỗ lời hứa được kiểm chứng bằng cảm nhận, và cũng là nơi trải nghiệm tốt có thể chuyển thành sự gắn bó lâu dài.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e1121caa-3a64-47e1-b3e1-ab0e45b07118','adad8f5f-ada1-47c3-be24-31de8d628395',24,'text','Personal Brand tạo niềm tin ban đầu, Media Network mở rộng độ phủ, còn Clinic System biến kỳ vọng thành trải nghiệm thật. Ba trụ này không thay nhau làm việc; chúng nâng nhau lên, và khi cả ba cùng mạnh, vòng quay tăng trưởng sẽ không còn phụ thuộc vào một nguồn duy nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('412fdf99-2fb5-448c-86fd-fe9323399a92','08-mo-tang-empire-u-plus','173da196-5678-493a-991d-3efda4569c2a',3,'Growth Engine','growth-engine',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7fa7d0f0-327c-480d-bc30-b09f5a4576e6','412fdf99-2fb5-448c-86fd-fe9323399a92',25,'image',NULL,'book/08-mo-tang-empire-u-plus/3c48403e-86b6-4271-b073-ca48f1a657e2-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ecd44da2-24ef-4435-b7d3-3d17226799d0','412fdf99-2fb5-448c-86fd-fe9323399a92',26,'text','Nếu ba trụ là phần **xương**, thì Growth Engine là phần **động cơ**. Đây là nơi Content, Ads, CRM, Sales, Data và Automation phối hợp với nhau để biến sự chú ý thành lịch hẹn, biến lịch hẹn thành cơ hội điều trị, và biến cơ hội điều trị thành tăng trưởng có thể đo lường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a99c3aaa-96ea-43e8-b399-f7415617ad6b','412fdf99-2fb5-448c-86fd-fe9323399a92',27,'text','Tôi rất thích gọi nó là động cơ, vì một động cơ đúng nghĩa không chỉ chạy mạnh; nó còn phải chạy đều.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4ef84f95-c680-4fd0-9375-3c440354ce0c','412fdf99-2fb5-448c-86fd-fe9323399a92',28,'text','- Content tạo sự quan tâm- Ads mở rộng tệp tiếp cận- CRM giữ mạch quan hệ- Sales chuyển sự quan tâm thành quyết định- Data cho ta biết hệ thống đang mạnh ở đâu yếu ở đâu- Automation giúp mọi thứ không bị phụ thuộc quá nhiều vào trí nhớ hay cảm hứng của con người.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2ed59ac6-2414-4fac-8ccb-cb729a2b0538','412fdf99-2fb5-448c-86fd-fe9323399a92',29,'text','Khi Growth Engine vận hành tốt, phòng khám không cần phải chạy theo từng cơ hội riêng lẻ. Hệ thống sẽ tự tạo đà cho chính nó, và đó là lúc ta bắt đầu thấy rõ sự khác nhau giữa một phòng khám “có khách” và một phòng khám “có hệ thống”.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0bc065e3-7dc9-4d1b-a9a8-7e082746df96','08-mo-tang-empire-u-plus','173da196-5678-493a-991d-3efda4569c2a',3,'Trust Assets','trust-assets',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e1b9e5f6-cf9c-4b51-b1ea-2ec4de64f91a','0bc065e3-7dc9-4d1b-a9a8-7e082746df96',30,'image',NULL,'book/08-mo-tang-empire-u-plus/8bacf423-bb55-4a98-a6ce-8908d08815a7-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e835dcee-83a7-4723-a9bc-6cc8ff611f5b','0bc065e3-7dc9-4d1b-a9a8-7e082746df96',31,'text','Nhưng tăng trưởng không thể bền nếu thiếu niềm tin. Vì vậy, phía sau Growth Engine là **Trust Assets** những tài sản giúp phòng khám không chỉ nói hay, mà còn cho người khác thấy được thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b73d3cb6-228e-4ac5-9552-df5091762fa1','0bc065e3-7dc9-4d1b-a9a8-7e082746df96',32,'text','Ở đây, tôi xem case thật, review, Google Map, Website và Livestream là những tài sản rất quan trọng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('081ba544-b3f2-48ec-9ab3-2749c27cd92e','0bc065e3-7dc9-4d1b-a9a8-7e082746df96',33,'text','- Case thật chứng minh năng lực. - Review chứng minh trải nghiệm. - Google Map chứng minh sự hiện diện và độ tin cậy. - Website là nơi hệ thống hóa thông tin. - Livestream là cách biến sự hiện diện thành kết nối trực tiếp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3af4567d-8fb8-41c7-83fb-fa02a8968aa5','0bc065e3-7dc9-4d1b-a9a8-7e082746df96',34,'text','Điều khiến Trust Assets đặc biệt là chúng không chỉ giúp bán hàng. Chúng giúp rút ngắn thời gian ra quyết định. Khi người bệnh tìm kiếm, so sánh và kiểm tra, họ thường không mua ngay từ lời quảng cáo; họ mua từ cảm giác rằng phòng khám này có thật, có uy tín, có người thật làm thật, và có dấu vết đáng tin để họ bám vào',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b8ff519b-ddde-4b64-8c9c-3b44521c92a6','08-mo-tang-empire-u-plus','173da196-5678-493a-991d-3efda4569c2a',3,'Customer Journey','customer-journey',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3074f0a7-c61f-4e0d-9655-2f3a0095d6e3','b8ff519b-ddde-4b64-8c9c-3b44521c92a6',35,'image',NULL,'book/08-mo-tang-empire-u-plus/266339e0-2a0d-4ac1-a70d-b0dbdcae91b3-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('398dbd89-36d1-410a-bb61-e75969e9aa9d','b8ff519b-ddde-4b64-8c9c-3b44521c92a6',36,'text','Từ niềm tin, khách hàng đi vào **Customer Journey** một hành trình rất người, rất tự nhiên, nơi quyết định không đến trong một bước mà được hình thành qua nhiều lần chạm. Thường sẽ là một chuỗi đi từ Traffic đến Trust, rồi Relationship, Authority Check, Search Layer và cuối cùng mới đến Conversion.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d04be474-8822-4f33-adb8-7849328ecaa8','b8ff519b-ddde-4b64-8c9c-3b44521c92a6',37,'text','Tôi thích nhìn hành trình này như cách người bệnh tự hỏi rất khẽ nhưng rất thật:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f21dc88d-39e7-45cd-80f2-bcb9a50d08f1','b8ff519b-ddde-4b64-8c9c-3b44521c92a6',38,'text','- Phòng khám này có đáng tin không?- Bác sĩ này có phù hợp với mình không?- Họ có giải thích đủ rõ không?- Mình có thấy an tâm khi bước vào không?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6ba2d641-b302-4c82-b488-bf145dd3422d','b8ff519b-ddde-4b64-8c9c-3b44521c92a6',39,'text','Chính những câu hỏi ấy tạo nên từng lớp chạm trong hành trình khách hàng, và cũng chính chúng quyết định người bệnh sẽ tiến thêm một bước hay dừng lại ở ngưỡng lưỡng lự.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('640c1a1b-0d0c-453c-86d1-3c45f5efc58e','b8ff519b-ddde-4b64-8c9c-3b44521c92a6',40,'text','Khi hiểu Customer Journey, ta sẽ bớt kỳ vọng vào những chuyển đổi vội vàng. Thay vào đó, ta thiết kế từng điểm chạm để người bệnh đi qua từng lớp một cách tự nhiên hơn, nhẹ hơn, và tin hơn như thể hệ thống đang lặng lẽ dẫn họ đến đúng nơi mình cần đến.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('339d12a2-024c-4791-b353-b8630e18f183','08-mo-tang-empire-u-plus','173da196-5678-493a-991d-3efda4569c2a',3,'Patient Experience','patient-experience',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d89deb3a-38cd-45b5-a665-ea09ee04b805','339d12a2-024c-4791-b353-b8630e18f183',41,'text','Nếu Customer Journey là con đường người bệnh đi vào, thì **Patient Experience** là cảm giác họ mang theo khi đi trên con đường ấy. Tôi luôn tin rằng trải nghiệm không phải là một điểm, mà là một chuỗi: khám → điều trị → chăm sóc → tái khám → review. Và chính chuỗi trải nghiệm ấy quyết định họ chỉ ghé qua một lần, hay ở lại đủ lâu để trở thành người gắn bó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('136cdc29-c6c0-49c8-b7cd-199c669047c8','339d12a2-024c-4791-b353-b8630e18f183',42,'text','Điều quan trọng là: người bệnh có thể quên nhiều chi tiết kỹ thuật, nhưng họ sẽ nhớ rất lâu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('41c3a214-425b-4f90-869e-e8387b0f68c5','339d12a2-024c-4791-b353-b8630e18f183',43,'text','- Cách họ được đón tiếp.- Cách họ được giải thích.- Cách họ được theo sát.- Và cảm giác an tâm họ có được trong suốt hành trình ấy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e3ed7875-4465-4193-b126-845a16a2d059','339d12a2-024c-4791-b353-b8630e18f183',44,'text','Nếu Patient Experience tốt, phòng khám không chỉ giữ được bệnh nhân; phòng khám còn tạo ra những người sẵn sàng quay lại và giới thiệu người khác.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('01ecb138-ac0b-442e-9ac1-3496fa2cdc47','08-mo-tang-empire-u-plus','173da196-5678-493a-991d-3efda4569c2a',3,'Referral Ecosystem','referral-ecosystem',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b706ba77-26af-4643-933d-bafdc41f85b6','01ecb138-ac0b-442e-9ac1-3496fa2cdc47',45,'text','Khi trải nghiệm đủ tốt, nó sẽ tự sinh ra **Referral Ecosystem**. Đây là lúc lời giới thiệu, testimonial và những case mới xuất hiện như một kết quả rất tự nhiên của sự hài lòng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ef7ef18d-5696-45b9-9aac-660310580d44','01ecb138-ac0b-442e-9ac1-3496fa2cdc47',46,'text','Tôi không xem referral là điều may rủi. Tôi xem nó là một **cơ chế**. Nếu phòng khám làm tốt ở những điểm chạm quan trọng, người bệnh sẽ sẵn sàng kể lại câu chuyện của mình, chia sẻ trải nghiệm của mình, và giới thiệu người quen của mình. Điều đó mạnh hơn nhiều so với việc chỉ cố gắng “xin referral” một cách rời rạc, vì nó đi ra từ niềm tin thật chứ không phải từ một lời nhắc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a7eeb54-2d4f-4cda-ace1-35fabbe83982','01ecb138-ac0b-442e-9ac1-3496fa2cdc47',47,'text','Khi Referral Ecosystem vận hành đúng, nó tạo ra một dòng khách mới đã có niềm tin từ trước. Và đó là một lợi thế rất lớn, vì người được giới thiệu thường ra quyết định nhanh hơn, tin hơn, và bước vào phòng khám với ít ngờ vực hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0b1f9ac4-0434-4ab9-92a8-16eb2b4b0d21','08-mo-tang-empire-u-plus','173da196-5678-493a-991d-3efda4569c2a',3,'Patient Community','patient-community',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('194f8cc4-02e2-436c-bce1-b6aeb00ab26b','0b1f9ac4-0434-4ab9-92a8-16eb2b4b0d21',48,'text','Xa hơn một bước nữa là **Patient Community**. Tôi thích tầng này vì nó cho thấy phòng khám không chỉ dừng lại ở việc điều trị, mà còn xây được một mối quan hệ dài hạn với bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ccb1490f-1da0-48fb-8693-480b7b1ed1c1','0b1f9ac4-0434-4ab9-92a8-16eb2b4b0d21',49,'text','Ở tầng này, người bệnh được giáo dục, được chăm sóc định kỳ và được giữ kết nối với phòng khám trong thời gian dài. Họ không còn là “khách một lần”, mà dần trở thành một cộng đồng gắn bó. Và khi cộng đồng được nuôi dưỡng tốt, nó sẽ trở thành một lớp giữ chân cực kỳ mạnh, giúp phòng khám không phải luôn bắt đầu lại từ đầu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('03d2bb80-8fd0-4ad2-a3e7-eff1bca9b5c0','0b1f9ac4-0434-4ab9-92a8-16eb2b4b0d21',50,'text','Một phòng khám thật sự chuyển từ tư duy giao dịch sang tư duy quan hệ. Mà đã là quan hệ, thì chiều sâu quan trọng hơn số lượng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('79722668-9e9a-4e67-ba59-5840c5e35192','08-mo-tang-empire-u-plus','173da196-5678-493a-991d-3efda4569c2a',3,'Education / Product Layer','education-product-layer',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('25a7a99d-f939-4b7a-995c-dfff2a4dc04f','79722668-9e9a-4e67-ba59-5840c5e35192',51,'text','Cuối cùng là **Education / Product Layer**. Đây là lớp mà phòng khám mở rộng giá trị qua membership, sản phẩm, workshop, tài liệu và đào tạo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('baafcfef-bb3a-4907-96aa-3f0c35536140','79722668-9e9a-4e67-ba59-5840c5e35192',52,'text','Tôi xem đây là một tầng rất đẹp, vì nó cho phép chuyên môn không chỉ nằm trong ghế điều trị, mà còn được chuyển hóa thành tài sản giáo dục và giá trị cộng thêm. Khi phòng khám có lớp giáo dục tốt, người bệnh hiểu hơn, tin hơn, chủ động hơn và gắn bó hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e3fb3d42-9c6f-40d6-b87a-3f7397419009','79722668-9e9a-4e67-ba59-5840c5e35192',53,'text','Quan trọng hơn, lớp này còn giúp quay lại nuôi Brand, Media và Referral. Nghĩa là phòng khám không chỉ tạo ra doanh thu từ điều trị; phòng khám còn tạo ra giá trị lan tỏa từ tri thức, trải nghiệm và cộng đồng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cd8c76bb-e207-4f5e-9564-4d92586f8611','08-mo-tang-empire-u-plus',NULL,2,'8.5 Kết luận','85-ket-luan',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0af22251-9d50-498e-94bc-028db23eb7dd','cd8c76bb-e207-4f5e-9564-4d92586f8611',54,'text','Khi tôi nhìn toàn bộ tầng 2, tôi thấy một điều rất rõ: đây không phải là một phễu đơn lẻ, mà là một hệ sinh thái quay vòng. Brand nuôi Media, Media nuôi Trust, Trust nuôi Journey, Journey nuôi Experience, Experience nuôi Referral, Referral nuôi Community, và Community lại quay về nuôi chính Brand.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fdb72efd-6fc3-4469-baf5-bc457c2d3d10','cd8c76bb-e207-4f5e-9564-4d92586f8611',55,'text','Và chúng ta sẽ bắt đầu đi chi tiết toàn bộ Master Map trong các chương tiếp theo.',NULL,NULL,NULL,NULL,NULL);
